#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
     // Function to find the minimum number of intervals to remove to make all intervals non-overlapping
    int eraseOverlapIntervals(vector<vector<int>>& intervals) {

        // Total number of intervals
        int n = intervals.size();

        // Store the max size of non-overlapping subset
        int maxValid = 0;

        // Try all subsets using bitmasking
        for (int mask = 0; mask < (1 << n); ++mask) {

            // Vector to hold selected subset
            vector<vector<int>> subset;

            // Construct subset from bitmask
            for (int i = 0; i < n; ++i) {
                if (mask & (1 << i))
                    subset.push_back(intervals[i]);
            }

            // Sort subset by start time
            sort(subset.begin(), subset.end());

            // Check if it's non-overlapping
            bool valid = true;
            for (int i = 1; i < subset.size(); ++i) {
                if (subset[i][0] < subset[i-1][1]) {
                    valid = false;
                    break;
                }
            }

            // If valid, update maxValid size
            if (valid)
                maxValid = max(maxValid, (int)subset.size());
        }

        // Answer = total - size of max valid subset
        return n - maxValid;
    }
};
// Driver Code
int main() {
    Solution sol;
    vector<vector<int>> intervals = {{1,2}, {2,3}, {3,4}, {1,3}};
    cout << "Minimum intervals to remove: " << sol.eraseOverlapIntervals(intervals) << endl;
    return 0;
}

